function slugify(value) {
  return String(value || 'experiment')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 80) || 'experiment';
}

const now = new Date().toISOString();
const slug = slugify($json.idea_text || 'experiment');
const experimentId = `exp_${now.slice(0, 10).replace(/-/g, '')}_${slug.replace(/-/g, '_')}`;

return [{
  json: {
    ...$json,
    submitted_at: now,
    experiment_slug: slug,
    experiment_id: experimentId,
    iteration_number: 1,
    iteration_history: [],
    normalized_request: {
      idea_text: $json.idea_text,
      submitter_name: $json.submitter_name,
      team: $json.team,
      channel: $json.channel,
      business_context: $json.business_context,
      clarification_answers: $json.clarification_answers,
      baseline_inputs: $json.baseline_inputs,
      reviewer_action: $json.reviewer_action,
      reviewer_comments: $json.reviewer_comments,
      experiment_id: experimentId,
      experiment_slug: slug,
      submitted_at: now
    }
  }
}];

