const prior = $('Initialize Experiment Context').first().json;
const content = $json.choices?.[0]?.message?.content || $json.output_text || '';
let brief;

try {
  brief = typeof content === 'string' ? JSON.parse(content) : content;
} catch (error) {
  brief = {
    experiment_name: 'Parsing Error',
    experiment_slug: prior.experiment_slug || 'experiment',
    brief_status: 'needs_clarification',
    business_problem: '',
    hypothesis: '',
    target_segment: '',
    primary_metric: '',
    secondary_metrics: [],
    guardrail_metrics: [],
    experiment_type: '',
    recommended_test_design: '',
    randomization_unit: '',
    expected_effect: '',
    success_criteria: '',
    instrumentation_requirements: [],
    assumptions: ['Model output could not be parsed as JSON.'],
    risks: ['Malformed intake agent output.'],
    implementation_notes: '',
    missing_information: ['Valid structured brief JSON']
  };
}

const required = ['business_problem', 'hypothesis', 'target_segment', 'primary_metric', 'randomization_unit'];
const missing = [
  ...(Array.isArray(brief.missing_information) ? brief.missing_information : []),
  ...required.filter((key) => !brief[key] || String(brief[key]).trim() === '')
].filter((value, index, array) => array.indexOf(value) === index);

return [{
  json: {
    ...prior,
    structured_brief: {
      ...brief,
      experiment_slug: brief.experiment_slug || prior.experiment_slug,
      experiment_name: brief.experiment_name || 'Untitled Experiment'
    },
    missing_information: missing,
    is_complete: missing.length === 0 && brief.brief_status !== 'needs_clarification'
  }
}];

