let prior;
try {
  prior = $('Validate Updated Brief').first().json;
} catch (error) {
  try {
    prior = $('Update Brief & Increment Iteration').first().json;
  } catch (innerError) {
    prior = $('Validate & Structure Brief').first().json;
  }
}

const content = $json.choices?.[0]?.message?.content || $json.output_text || '';
let review;

try {
  review = typeof content === 'string' ? JSON.parse(content) : content;
} catch (error) {
  review = {
    review_summary: 'Unable to parse review output.',
    hypothesis_testability: { score: 2, comment: 'Parsing failure.' },
    metric_quality: { score: 2, comment: 'Parsing failure.' },
    experiment_design_fit: { score: 2, comment: 'Parsing failure.' },
    instrumentation_readiness: { score: 2, comment: 'Parsing failure.' },
    bias_and_confounding_risks: ['Review output parsing error'],
    randomization_review: 'Unknown',
    missing_guardrails: ['Unknown due to parsing error'],
    recommended_experiment_approach: 'Needs manual review',
    blockers: [{ severity: 'medium', issue: 'Review output could not be parsed.' }],
    revision_actions: ['Re-run review or inspect model response.'],
    reviewer_confidence: 'low'
  };
}

const deterministicBlockers = [];
const brief = prior.structured_brief || {};
if (!brief.primary_metric) deterministicBlockers.push({ severity: 'critical', issue: 'Primary metric is missing.' });
if (!brief.randomization_unit) deterministicBlockers.push({ severity: 'critical', issue: 'Randomization unit is missing.' });
if (!Array.isArray(brief.guardrail_metrics) || brief.guardrail_metrics.length === 0) deterministicBlockers.push({ severity: 'medium', issue: 'Guardrail metrics are missing.' });

return [{
  json: {
    ...prior,
    review_assessment: {
      ...review,
      blockers: [...(Array.isArray(review.blockers) ? review.blockers : []), ...deterministicBlockers]
    }
  }
}];

const brief = $json.structured_brief || {};
const review = $json.review_assessment || {};
const blockers = Array.isArray(review.blockers) ? review.blockers : [];

function scoreFromReview(reviewDimension, fallback = 2) {
  return Number(reviewDimension?.score || fallback);
}

function hasValue(value) {
  if (Array.isArray(value)) return value.length > 0;
  return value !== undefined && value !== null && String(value).trim() !== '';
}

const hypothesisClarity = scoreFromReview(review.hypothesis_testability, hasValue(brief.hypothesis) ? 3 : 1);
const measurementReadiness = scoreFromReview(review.metric_quality, hasValue(brief.primary_metric) ? 3 : 1);
const instrumentationReadiness = scoreFromReview(review.instrumentation_readiness, hasValue(brief.instrumentation_requirements) ? 3 : 1);
const businessImpactPotential = hasValue(brief.expected_effect) ? 4 : 2;
const feasibility = hasValue(brief.randomization_unit) && hasValue(brief.experiment_type) && hasValue(brief.target_segment) ? 4 : 2;

let riskLevel = 2;
const riskCount = Array.isArray(review.bias_and_confounding_risks) ? review.bias_and_confounding_risks.length : 0;
if (riskCount >= 4) riskLevel = 5;
else if (riskCount >= 3) riskLevel = 4;
else if (riskCount >= 2) riskLevel = 3;
if ((brief.risks || []).length >= 4) riskLevel = Math.max(riskLevel, 4);

const criticalBlockers = blockers.filter((b) => b.severity === 'critical');
const mediumBlockers = blockers.filter((b) => b.severity === 'medium');
const readinessScore = hypothesisClarity + measurementReadiness + instrumentationReadiness + businessImpactPotential + feasibility + (5 - riskLevel);

let suggestedRecommendation = 'Needs Revision';
if (criticalBlockers.length > 0 || readinessScore < 15) suggestedRecommendation = 'Not Recommended Yet';
else if (readinessScore >= 22 && mediumBlockers.length === 0) suggestedRecommendation = 'Ready to Launch';

return [{
  json: {
    ...$json,
    readiness_scoring: {
      dimensions: {
        hypothesis_clarity: hypothesisClarity,
        measurement_readiness: measurementReadiness,
        instrumentation_readiness: instrumentationReadiness,
        business_impact_potential: businessImpactPotential,
        feasibility,
        risk_level: riskLevel
      },
      blocker_counts: {
        critical: criticalBlockers.length,
        medium: mediumBlockers.length,
        total: blockers.length
      },
      readiness_score: readinessScore,
      suggested_recommendation: suggestedRecommendation
    }
  }
}];

const inputs = $json.baseline_inputs || {};

function rate(conversions, visitors) {
  return visitors > 0 ? conversions / visitors : 0;
}

function round(value, digits = 4) {
  const factor = 10 ** digits;
  return Math.round(value * factor) / factor;
}

function zCritical(alpha = 0.05) {
  return alpha === 0.1 ? 1.64 : 1.96;
}

function zPower(power = 0.8) {
  if (power >= 0.9) return 1.28;
  if (power >= 0.85) return 1.04;
  return 0.84;
}

function approximateSampleSize(baselineRate, expectedRelativeLift, alpha = 0.05, power = 0.8) {
  if (!baselineRate || !expectedRelativeLift) return null;
  const p1 = baselineRate;
  const p2 = baselineRate * (1 + expectedRelativeLift);
  const delta = Math.abs(p2 - p1);
  if (delta === 0) return null;
  const pooled = (p1 + p2) / 2;
  const za = zCritical(alpha);
  const zb = zPower(power);
  const numerator = Math.pow(za * Math.sqrt(2 * pooled * (1 - pooled)) + zb * Math.sqrt(p1 * (1 - p1) + p2 * (1 - p2)), 2);
  return Math.ceil(numerator / Math.pow(delta, 2));
}

const baselineConversions = Number(inputs.baseline_conversions || 0);
const baselineVisitors = Number(inputs.baseline_visitors || 0);
const variantConversions = Number(inputs.variant_conversions || 0);
const variantVisitors = Number(inputs.variant_visitors || 0);
const expectedRelativeLift = Number(inputs.expected_relative_lift || 0.02);
const dailyEligibleTraffic = Number(inputs.daily_eligible_traffic || 0);
const baselineRate = rate(baselineConversions, baselineVisitors);
const variantRate = rate(variantConversions, variantVisitors);
const absoluteUplift = variantRate - baselineRate;
const relativeLift = baselineRate === 0 ? 0 : absoluteUplift / baselineRate;
const sampleSizePerVariant = approximateSampleSize(baselineRate, expectedRelativeLift, 0.05, 0.8);
const estimatedTestDurationDays = sampleSizePerVariant && dailyEligibleTraffic ? Math.ceil(sampleSizePerVariant / (dailyEligibleTraffic / 2)) : null;

return [{
  json: {
    ...$json,
    stats_summary: {
      baseline_rate: round(baselineRate, 4),
      variant_rate: round(variantRate, 4),
      absolute_uplift: round(absoluteUplift, 4),
      relative_lift: round(relativeLift, 4),
      sample_size_per_variant_approx: sampleSizePerVariant,
      estimated_test_duration_days: estimatedTestDurationDays,
      significance_summary: baselineVisitors && variantVisitors ? 'Directional estimate available from supplied baseline inputs.' : 'No observed variant data supplied; using planning-style estimates only.'
    }
  }
}];

